sql:
SELECT session_id, agent, result
FROM problem_solving_sessions
WHERE type = 'practice';

SELECT COUNT(*) 
FROM problem_solving_sessions
WHERE session_status = 'completed';

external_knowledge:
; 
; A collaborative problem-solving session is considered successful when the result is 'Success' and the session status is 'Completed'. 
; Average performance is measured by the average correctness of the steps taken during the session.

sql:
SELECT type, COUNT(DISTINCT problem) AS unique_problems_solved
FROM problem_solving_sessions
GROUP BY type;
